ee:message.ee:set-payload:
%dw 2.0
output application/json
fun lbToKg(lb) = ((lb as Number) * 0.453592) round 3
fun normalizeUom(uom) =
    upper(uom) match {
        case "EA" -> "EA"
        case "EACH" -> "EA"
        case "CS" -> "CAR"
        case "CASE" -> "CAR"
        else -> "EA"
    }
---
{
  deliveryPostingRequest: {
    externalReference: payload.shipment.shipmentId,
    salesOrderNumber: payload.order.orderNumber,
    deliveryDate: payload.shipment.shipDate,
    shippingPoint: payload.shipment.warehouse.code,
    plant: payload.shipment.warehouse.plantCode,
    soldToParty: payload.customer.erpCustomerNumber,
    shipToParty: {
      name: payload.customer.name,
      addressLine1: payload.customer.address.line1,
      city: payload.customer.address.city,
      postalCode: payload.customer.address.postalCode,
      countryCode: payload.customer.address.country
    },
    headerText: "Shipment posted from WMS via MuleSoft",
    handlingInstructions:
      if ((payload.shipment.expedited default false) == true)
        "PRIORITY HANDLING REQUIRED"
      else
        "STANDARD FULFILLMENT",
    totalGrossWeightKg: lbToKg(payload.shipment.totalWeightLb default 0),
    packageCount: sizeOf(payload.shipment.packages default []),
    carrier: {
      code: payload.shipment.carrier.scac,
      serviceLevel:
        upper(payload.shipment.carrier.serviceLevel default "GROUND") match {
          case "NEXT_DAY" -> "EXPRESS"
          case "2_DAY" -> "EXPRESS"
          else -> "STANDARD"
        }
    },
    lineItems: (payload.shipment.lines default []) map (line, index) -> {
      itemNumber: ((index + 1) * 10) as String {format: "000000"},
      materialNumber: line.sku,
      batchNumber: line.lot default null,
      deliveredQuantity: line.quantityShipped,
      salesUnit: normalizeUom(line.uom),
      storageLocation:
        if ((line.temperatureZone default "AMBIENT") == "COLD")
          "C001"
        else
          "A001",
      valuationType:
        if ((line.inventoryType default "SELLABLE") == "QC_HOLD")
          "QH"
        else
          "STD",
      serialNumbers: (line.serialNumbers default []) map (sn) -> {
        serialNumber: sn
      }
    },
    partnerReferences: [
      {
        type: "BOL",
        value: payload.shipment.billOfLading
      },
      {
        type: "TRACKING",
        value: payload.shipment.trackingNumber
      }
    ] filter ($.value != null)
  }
}
